#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    ll n,x;    cin >> n >> x;    ll maxi_possible=0;    vll a(n);    for(int i=0; i<n; i++){         cin >> a[i];         maxi_possible +=  ceil((double)a[i]/x);     }    ll mini_possible = 0;    for(int i=0;i<=a.size()-1;i++){        mini_possible+=a[i];            }    mini_possible= ceil((double)mini_possible/x);    cout << mini_possible << " " << maxi_possible << "\n"; } // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}